<?php
namespace App\Models;use Illuminate\Database\Eloquent\Model;
class SecurityGovernanceNotification extends Model{protected $fillable=['notification_number','type','severity','status','subject','message','related_type','related_id','assigned_to_id','created_by_id','acknowledged_by_id','resolved_by_id','acknowledged_at','resolved_at','metadata','owner_id','escalation_level','escalated_at','due_at','last_escalated_by_id','resolution_required'];protected function casts():array{return ['acknowledged_at'=>'datetime','resolved_at'=>'datetime','escalated_at'=>'datetime','due_at'=>'datetime','resolution_required'=>'boolean','metadata'=>'array'];}public function events(){return $this->hasMany(SecurityGovernanceNotificationEvent::class)->latest('created_at');}public function owner(){return $this->belongsTo(User::class,'owner_id');}}
